// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Certification {
    // Thông tin người quản trị (Trường học)
    address public admin;

    constructor() {
        admin = msg.sender; // Người deploy contract sẽ là Admin
    }

    // Cấu trúc bằng cấp
    struct Diploma {
        uint256 id;
        string studentName;
        string major;       // Ngành học
        string classification; // Xếp loại
        uint256 issueDate;
        bool isValid;       // Trạng thái hiệu lực
    }

    // Lưu trữ: Map từ ID -> Thông tin bằng
    mapping(uint256 => Diploma) public diplomas;

    // Sự kiện để Frontend bắt được khi cấp bằng xong
    event DiplomaIssued(uint256 indexed id, string studentName);

    // Modifier: Chỉ Admin mới được gọi hàm này
    modifier onlyAdmin() {
        require(msg.sender == admin, "Ban khong co quyen (Only Admin)");
        _;
    }

    // 1. Chức năng Cấp bằng (Chỉ Admin)
    function issueDiploma(
        uint256 _id, 
        string memory _name, 
        string memory _major, 
        string memory _class
    ) public onlyAdmin {
        require(diplomas[_id].id == 0, "ID nay da ton tai!"); // Chặn trùng ID

        diplomas[_id] = Diploma(_id, _name, _major, _class, block.timestamp, true);
        emit DiplomaIssued(_id, _name);
    }

    // 2. Chức năng Tra cứu (Ai cũng dùng được)
    function verifyDiploma(uint256 _id) public view returns (string memory, string memory, string memory, uint256, bool) {
        require(diplomas[_id].id != 0, "Bang cap khong ton tai!");
        Diploma memory d = diplomas[_id];
        return (d.studentName, d.major, d.classification, d.issueDate, d.isValid);
    }

    // 3. Chức năng Thu hồi bằng (Chỉ Admin)
    function revokeDiploma(uint256 _id) public onlyAdmin {
        require(diplomas[_id].id != 0, "Bang cap khong ton tai!");
        diplomas[_id].isValid = false; // Vô hiệu hóa bằng
    }
}
